// Handle authorization form submission
app.post('/authorize', async (req, res) => {
  const { client_id, redirect_uri, scope, state, username, password, action } = req.body;

  const redirectUrl = new URL(redirect_uri);

  if (action === 'deny') {
    redirectUrl.searchParams.set('error', 'access_denied');
    redirectUrl.searchParams.set('error_description', 'User denied the request');
    if (state) redirectUrl.searchParams.set('state', state);
    return res.redirect(redirectUrl.toString());
  }

  // Authenticate user
  const user = users.get(username);
  if (!user) {
    return res.status(401).send('Invalid username or password. <a href="javascript:history.back()">Try again</a>');
  }

  const validPassword = await bcrypt.compare(password, user.password_hash);
  if (!validPassword) {
    return res.status(401).send('Invalid username or password. <a href="javascript:history.back()">Try again</a>');
  }

  // Generate authorization code
  const code = generateAuthorizationCode();
  const codeData = {
    client_id,
    redirect_uri,
    username: user.username,
    scope,
    created_at: Date.now(),
  };

  await storeAuthorizationCode(code, codeData);

  redirectUrl.searchParams.set('code', code);
  if (state) redirectUrl.searchParams.set('state', state);

  console.log(`Authorization code issued for user=${username}, client=${client_id}`);
  res.redirect(redirectUrl.toString());
});

