app.post('/token', authenticateClient, async (req, res) => {
  const { grant_type } = req.body;
  const { clientId, clientSecret } = req;

  // Validate client
  const client = clients.get(clientId);
  if (!client) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Unknown client',
    });
  }

  const validSecret = await bcrypt.compare(clientSecret, client.client_secret_hash);
  if (!validSecret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Invalid client credentials',
    });
  }

  if (!client.grants.includes(grant_type)) {
    return res.status(400).json({
      error: 'unsupported_grant_type',
      error_description: `Grant type '${grant_type}' not allowed for this client`,
    });
  }

  if (grant_type === 'authorization_code') {
    return handleAuthorizationCodeGrant(req, res, client);
  } else if (grant_type === 'refresh_token') {
    return handleRefreshTokenGrant(req, res, client);
  } else {
    return res.status(400).json({
      error: 'unsupported_grant_type',
      error_description: 'Supported grant types: authorization_code, refresh_token',
    });
  }
});

async function handleAuthorizationCodeGrant(req, res, client) {
  const { code, redirect_uri } = req.body;

  if (!code) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Authorization code is required',
    });
  }

  const codeData = await getAndDeleteAuthorizationCode(code);
  if (!codeData) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid or expired authorization code',
    });
  }

  // Validate that the code was issued to this client
  if (codeData.client_id !== client.client_id) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code was not issued to this client',
    });
  }

  // Validate redirect_uri matches
  if (codeData.redirect_uri && redirect_uri !== codeData.redirect_uri) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'redirect_uri mismatch',
    });
  }

  const user = users.get(codeData.username);
  if (!user) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'User no longer exists',
    });
  }

  // Generate tokens
  const accessTokenPayload = {
    sub: user.username,
    email: user.email,
    client_id: client.client_id,
    scope: codeData.scope,
    token_type: 'access_token',
    jti: uuidv4(),
  };

  const accessToken = generateAccessToken(accessTokenPayload);
  const refreshToken = generateRefreshToken();

  // Store refresh token in Redis with 1 year TTL
  // NOTE: This refresh token is reusable multiple times without rotation
  const refreshTokenData = {
    token: refreshToken,
    username: user.username,
    client_id: client.client_id,
    scope: codeData.scope,
    created_at: Date.now(),
    last_used_at: null,
    use_count: 0,
  };

  await storeRefreshToken(refreshToken, refreshTokenData);
  await trackUserRefreshToken(user.username, refreshToken);

  console.log(`Tokens issued: user=${user.username}, client=${client.client_id}, refresh_token_expiry=1year`);

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 900, // 15 minutes in seconds
    refresh_token: refreshToken,
    scope: codeData.scope,
  });
}

async function handleRefreshTokenGrant(req, res, client) {
  const { refresh_token, scope } = req.body;

  if (!refresh_token) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Refresh token is required',
    });
  }

  const tokenData = await getRefreshToken(refresh_token);
  if (!tokenData) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid or expired refresh token',
    });
  }

  // Validate client matches
  if (tokenData.client_id !== client.client_id) {
    console.warn(`Refresh token client mismatch: expected=${tokenData.client_id}, got=${client.client_id}`);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Refresh token was not issued to this client',
    });
  }

  const user = users.get(tokenData.username);
  if (!user) {
    await revokeRefreshToken(refresh_token);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'User no longer exists',
    });
  }

  // Handle scope narrowing
  const originalScopes = tokenData.scope.split(' ');
  let effectiveScope = tokenData.scope;

  if (scope) {
    const requestedScopes = scope.split(' ');
    const invalidScopes = requestedScopes.filter(s => !originalScopes.includes(s));
    if (invalidScopes.length > 0) {
      return res.status(400).json({
        error: 'invalid_scope',
        error_description: `Cannot request scopes not in original grant: ${invalidScopes.join(', ')}`,
      });
    }
    effectiveScope = scope;
  }

  // Issue new access token (reuse same refresh token - no rotation)
  const accessTokenPayload = {
    sub: user.username,
    email: user.email,
    client_id: client.client_id,
    scope: effectiveScope,
    token_type: 'access_token',
    jti: uuidv4(),
  };

  const accessToken = generateAccessToken(accessTokenPayload);

  // Update refresh token metadata (reuse without rotation)
  tokenData.last_used_at = Date.now();
  tokenData.use_count += 1;

  // Re-store with same key - TTL does NOT reset (token keeps original expiry)
  // To keep original TTL, we get remaining TTL and set with that
  const remainingTTL = await redis.ttl(`refresh_token:${refresh_token}`);
  if (remainingTTL > 0) {
    await redis.setex(`refresh_token:${refresh_token}`, remainingTTL, JSON.stringify(tokenData));
  }

  console.log(`Access token refreshed: user=${user.username}, client=${client.client_id}, refresh_use_count=${tokenData.use_count}`);

  // Return same refresh token (no rotation)
  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 900,
    refresh_token: refresh_token, // Same token returned - reusable
    scope: effectiveScope,
  });
}

// Token revocation endpoint (RFC 7009)
app.post('/revoke', authenticateClient, async (req, res) => {
  const { token, token_type_hint } = req.body;
  const { clientId, clientSecret } = req;

  const client = clients.get(clientId);
  if (!client) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  const validSecret = await bcrypt.compare(clientSecret, client.client_secret_hash);
  if (!validSecret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  if (!token) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Token is required',
    });
  }

  if (!token_type_hint || token_type_hint === 'refresh_token') {
    const tokenData = await getRefreshToken(token);
    if (tokenData) {
      if (tokenData.client_id !== client.client_id) {
        // RFC 7009: respond with 200 even if token doesn't belong to client
        return res.sendStatus(200);
      }
      await revokeRefreshToken(token);
      // Remove from user's token set
      const userTokensKey = `user_tokens:${tokenData.username}`;
      await redis.srem(userTokensKey, token);
      console.log(`Refresh token revoked: user=${tokenData.username}, client=${client.client_id}`);
    }
  }

  // Access tokens are JWTs and can't be directly revoked without a blacklist
  // For simplicity, we acknowledge the request
  res.sendStatus(200);
});

// Token introspection endpoint (RFC 7662)
app.post('/introspect', authenticateClient, async (req, res) => {
  const { token, token_type_hint } = req.body;
  const { clientId, clientSecret } = req;

  const client = clients.get(clientId);
  if (!client) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  const validSecret = await bcrypt.compare(clientSecret, client.client_secret_hash);
  if (!validSecret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  if (!token) {
    return res.json({ active: false });
  }

  // Try as access token (JWT)
  if (!token_type_hint || token_type_hint === 'access_token') {
    const payload = verifyAccessToken(token);
    if (payload) {
      return res.json({
        active: true,
        token_type: 'access_token',
        client_id: payload.client_id,
        username: payload.sub,
        scope: payload.scope,
        sub: payload.sub,
        exp: payload.exp,
        iat: payload.iat,
        jti: payload.jti,
      });
    }
  }

  // Try as refresh token
  if (!token_type_hint || token_type_hint === 'refresh_token') {
    const tokenData = await getRefreshToken(token);
    if (tokenData) {
      const ttl = await redis.ttl(`refresh_token:${token}`);
      return res.json({
        active: true,
        token_type: 'refresh_token',
        client_id: tokenData.client_id,
        username: tokenData.username,
        scope: tokenData.scope,
        sub: tokenData.username,
        exp: Math.floor(tokenData.created_at / 1000) + REFRESH_TOKEN_EXPIRY_SECONDS,
        iat: Math.floor(tokenData.created_at / 1000),
        ttl_remaining: ttl,
        use_count: tokenData.use_count,
        last_used_at: tokenData.last_used_at,
      });
    }
  }

  res.json({ active: false });
});

