// Client registration endpoint (simplified, for demo purposes)
app.post('/register-client', async (req, res) => {
  const { client_id, client_secret, redirect_uris, scopes } = req.body;

  if (!client_id || !client_secret || !redirect_uris || !Array.isArray(redirect_uris)) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'client_id, client_secret, and redirect_uris (array) are required',
    });
  }

  if (clients.has(client_id)) {
    return res.status(409).json({
      error: 'invalid_request',
      error_description: 'Client already exists',
    });
  }

  const clientSecretHash = await bcrypt.hash(client_secret, 10);
  const validScopes = (scopes || ['read']).filter(s => ['read', 'write', 'profile'].includes(s));

  clients.set(client_id, {
    client_id,
    client_secret_hash: clientSecretHash,
    redirect_uris,
    grants: ['authorization_code', 'refresh_token'],
    scopes: validScopes,
  });

  console.log(`New client registered: ${client_id}`);

  res.status(201).json({
    client_id,
    redirect_uris,
    grants: ['authorization_code', 'refresh_token'],
    scopes: validScopes,
    message: 'Client registered successfully',
  });
});

